import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';

function Home() {
  const [clientData, setClientData] = useState(null);

  useEffect(() => {
    try {
      const loggedInUser = localStorage.getItem('clientUser');
      if (loggedInUser) {
        setClientData(JSON.parse(loggedInUser));
      }
    } catch (error) {
      console.error("Error parsing user data:", error);
    }
  }, []);

  const handleLogout = () => {
    localStorage.removeItem('clientUser');
    setClientData(null);
    window.location.reload(); 
  };

  return (
    <div className="home-page" style={{ fontFamily: "'Poppins', sans-serif" }}>
      
      {/* 1. Modern Navbar */}
      <nav className="navbar navbar-expand-lg navbar-dark py-3" style={{ backgroundColor: '#121212', borderBottom: '1px solid #333' }}>
        <div className="container">
          <Link className="navbar-brand fw-bold fs-3" to="/">
            Freelancer <span style={{ color: '#4facfe' }}>Marketplace</span>
          </Link>
          <div className="collapse navbar-collapse justify-content-end">
            <ul className="navbar-nav gap-3 align-items-center">
              <li className="nav-item"><Link className="nav-link text-white" to="/">Home</Link></li>
              <li className="nav-item"><Link className="nav-link text-white" to="/services">Services</Link></li>
              {clientData ? (
                <li className="nav-item"><button onClick={handleLogout} className="btn btn-outline-danger btn-sm">Logout</button></li>
              ) : (
                <li className="nav-item"><Link className="btn btn-primary px-4 rounded-pill" to="/login">Login</Link></li>
              )}
            </ul>
          </div>
        </div>
      </nav>

      {/* 2. Hero Section */}
      <header className="hero-section text-white py-5 d-flex align-items-center" 
        style={{ 
          background: 'linear-gradient(135deg, #1e3c72 0%, #2a5298 100%)',
          minHeight: '75vh'
        }}>
        <div className="container text-center">
          <h1 className="display-2 fw-bold mb-3 mt-4" style={{ letterSpacing: '-2px' }}>
            Web <span style={{ color: '#ffc107' }}>Development</span>
          </h1>
          <p className="lead fs-4 mb-5 opacity-75 mx-auto" style={{ maxWidth: '700px' }}>
            Transforming your ideas into digital reality with high-quality, professional student freelancers.
          </p>
          <div className="d-flex justify-content-center gap-3">
            <Link to="/services" className="btn btn-warning btn-lg px-5 py-3 fw-bold rounded-pill shadow-lg">
              Explore Services
            </Link>
            <Link to="/contact" className="btn btn-outline-light btn-lg px-5 py-3 rounded-pill">
              Contact Us
            </Link> 
          </div>
        </div>
      </header>

      {/* 3. Features Section */}
      <section className="py-5 bg-white">
        <div className="container py-5">
          <div className="text-center mb-5">
            <h2 className="fw-bold fs-1">Why Choose Us?</h2>
            <div className="mx-auto" style={{ width: '60px', height: '4px', background: '#2a5298' }}></div>
          </div>
          <div className="row g-4 text-center">
            {[
              { icon: "🛡️", title: "Secure Payments", desc: "Your transactions are always safe with our system." },
              { icon: "🎓", title: "Verified Students", desc: "Work with top talent from various universities." },
              { icon: "⚡", title: "Fast Delivery", desc: "Quick turnaround for every project." }
            ].map((item, index) => (
              <div className="col-md-4" key={index}>
                <div className="card h-100 border-0 shadow-sm p-4 hover-card" style={{ transition: '0.3s' }}>
                  <div className="display-4 mb-3">{item.icon}</div>
                  <h4 className="fw-bold">{item.title}</h4>
                  <p className="text-muted">{item.desc}</p>
                </div>
              </div>
            ))}
          </div>
        </div>
      </section>

      {/* 4. Map Section */}
      <section id="contact" className="py-5 bg-light">
        <div className="container text-center">
          <h2 className="fw-bold mb-4">📍 Visit Us in <span className="text-primary">Nashik</span></h2>
          <div className="shadow-lg rounded-5 overflow-hidden mx-auto" style={{ maxWidth: '1000px', height: '400px', border: '8px solid white' }}>
            <iframe
              title="Nashik Map"
              src="https://www.google.com"
              width="100%" height="100%" style={{ border: 0 }} allowFullScreen="" loading="lazy"></iframe>
          </div>
        </div>
      </section>

      <footer className="py-5 text-center text-white" style={{ backgroundColor: '#121212' }}>
        <p className="mb-0 opacity-50">&copy; 2026 Student Freelancer Marketplace | Nashik</p>
      </footer>
    </div>
  );
}

export default Home;
